import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";
import pattern from "../slike/pattern4.jpg";
import { useEffect,useState } from "react";

export function PravljenjeRezervacije(){

        const[rezervacije,setRezervacije]=useState([]);
         const [sobe, setSobe] = useState([]);
         const [tipoviSobe,setTipSobe]=useState([]);

         const[ime,setIme]=useState("");


      useEffect(() => {
  Promise.all([
    fetch("http://localhost:8080/reservations/getReservationStatus/PENDING").then(res => res.json()),
    fetch("http://localhost:8080/rooms/all").then(res => res.json()),
    fetch("http://localhost:8080/tip-sobe/all").then(res => res.json())
  ])
  .then(([rezData, sobeData, tipSobeData]) => {
    if (rezData?.data?.values) setRezervacije(rezData.data.values);
    if (sobeData?.data?.values) setSobe(sobeData.data.values);
    if (tipSobeData?.data?.values) setTipSobe(tipSobeData.data.values);

    console.log("Rezervacije:", rezData);
    console.log("Sobe:", sobeData);
    console.log("Tipovi soba:", tipSobeData);
  })
  .catch(err => console.error("Greška pri učitavanju podataka:", err));
}, []);

    

    return(<>
   <div
        style={{
          minHeight: "100vh",
          display: "flex",
          flexDirection: "column",
          justifyContent: "space-between",
        }}
      >
        <NavBarRecepcionar />
  
        <div
          style={{
            backgroundImage: `url(${pattern})`,
            backgroundSize: "cover",
            backgroundPosition: "center",
            minHeight: "100vh",
            padding: "40px",
          }}
        >
        </div>
        
        <div>
            {
                rezervacije.map((rezervacija)=>{
                    <div>
                        <p>{rezervacija.datum_prijave}</p>
                        <p>{rezervacija.datum_odjave}</p>
                        <p>Broj osoba:{rezervacija.broj_osoba}</p>
                        <p>Iznos:{rezervacija.iznos}</p>

                    </div>
                })
            }
        </div>

        </div>

    <Footer />
    
    </>)
}
